/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven via EventBus with pluggable adapters.
 * - Services emit domain events (order:created, user:created, etc.)
 * - NotificationService subscribes to these events
 * - NotificationService delegates delivery to registered NotificationAdapters
 * - Each adapter handles a single channel (email, SMS, webhook, push, etc.)
 *
 * Constraints:
 * - All notifications must originate from EventBus events — no direct calls
 * - All delivery channels must implement NotificationAdapter interface
 * - NotificationType enum must be extended when adding new notification kinds
 */

/**
 * Supported notification channels.
 */
export type NotificationChannel = 'email' | 'sms' | 'push' | 'webhook' | 'in-app';

/**
 * Classification of notification types for routing and templating.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'account-updated';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID. */
  id: string;
  /** The type of notification, used for routing and templating. */
  type: NotificationType;
  /** The channel this notification should be delivered on. */
  channel: NotificationChannel;
  /** Recipient identifier (email address, phone number, user ID, etc.). */
  recipient: string;
  /** Notification subject/title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Optional structured metadata for adapter-specific needs. */
  metadata?: Record<string, string>;
}

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The notification ID. */
  notificationId: string;
  /** The channel that handled delivery. */
  channel: NotificationChannel;
  /** Error message if delivery failed. */
  error?: string;
  /** Timestamp of the delivery attempt. */
  timestamp: Date;
}

/**
 * Stored notification record.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, string>;
  result: NotificationResult;
  createdAt: Date;
}

/**
 * NotificationAdapter interface — the contract all delivery channels must implement.
 *
 * Architecture constraint: Every notification channel (email, SMS, push, webhook, etc.)
 * must implement this interface. The NotificationService routes notifications to
 * adapters based on their supported channel.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel type in src/models/notification.ts
 * 2. Create a new adapter class implementing NotificationAdapter
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * @param payload - The notification to deliver.
   * @returns The result of the delivery attempt.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails in-memory.
 * Replace the send() internals with a real email provider (SendGrid, SES, etc.)
 * while keeping the NotificationAdapter interface intact.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address. */
  from: string;
  /** Email provider name (for logging/identification). */
  provider: string;
}

export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  constructor(private config: EmailConfig) {}

  /**
   * Send an email notification.
   * Stub: stores the email in-memory and returns success.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: ${payload.subject}`,
    );

    const email: SentEmail = {
      to: payload.recipient,
      from: this.config.from,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      timestamp: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven with pluggable adapters.
 * - Subscribes to domain events via EventBus
 * - Transforms events into NotificationPayloads
 * - Delegates delivery to registered NotificationAdapters
 *
 * Constraints:
 * - All notifications are triggered by EventBus events — never by direct calls
 * - Delivery channels are added by registering adapters via registerAdapter()
 * - Each adapter handles exactly one NotificationChannel
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is allowed; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that should trigger notifications.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) =>
      this.handleUserUpdated(event),
    );
  }

  /**
   * Handle order created — send confirmation to the user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.sendNotification({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.sendNotification({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
    });
  }

  /**
   * Handle user updated — notify of account changes.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    await this.sendNotification({
      type: 'account-updated',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   */
  private async sendNotification(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, string>;
  }): Promise<NotificationResult> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);

    let result: NotificationResult;
    if (adapter) {
      result = await adapter.send(payload);
    } else {
      this.logger.warn(
        `No adapter registered for channel "${params.channel}", notification ${payload.id} not delivered`,
      );
      result = {
        success: false,
        notificationId: payload.id,
        channel: params.channel,
        error: `No adapter registered for channel: ${params.channel}`,
        timestamp: new Date(),
      };
    }

    const notification: Notification = {
      id: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      result,
      createdAt: new Date(),
    };
    this.notifications.push(notification);

    this.logger.info(
      `Notification ${payload.id} [${params.type}] via ${params.channel} to ${params.recipient}: ${result.success ? 'delivered' : 'failed'}`,
    );

    return result;
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications. Useful for testing.
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

